import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Home from './pages/home';
import SelectStack from './pages/selectStack';
import Questions from './pages/questions';
import Layout from './pages/layout';
import Results from './pages/results';
import { useState, useEffect } from 'react';
// import '';

function App() {
  const [selected, setSelected] = useState("");
  const [scores, setScores] = useState(0)

  use
  return (
    // <div className="min-h-screen bg-grid">
    <BrowserRouter>
      <Routes>
        <Route element={<Layout/>}>
          <Route path="/" element={<Home/>} />
          <Route path="/select" element={<SelectStack setSelected={setSelected} selected={selected} />} />
          <Route path="/questions/:selected" element={<Questions scores={scores} setScores={setScores} />} />
          <Route path="/results" element={<Results scores={scores} setScores={setScores} />} />
        </Route>
      </Routes>
    </BrowserRouter>
  );
}

export default App;
